def transform(nums):
    n = len(nums)
    zero_count = nums.count(0)

    if zero_count > 1:
        return [0] * n

    total_product = 1
    for num in nums:
        if num != 0:
            total_product *= num

    if zero_count == 1:
        return [total_product if num == 0 else 0 for num in nums]

    # no zeros
    left = [1] * n
    right = [1] * n
    result = [1] * n

    for i in range(1, n):
        left[i] = left[i-1] * nums[i-1]

    for i in range(n-2, -1, -1):
        right[i] = right[i+1] * nums[i+1]

    for i in range(n):
        result[i] = left[i] * right[i]

    return result

