def transform(nums):
    if len(nums) < 2:
        return []

    result = []
    for i in range(len(nums)):
        if i == 0:
            result.append(nums[1])
        elif i == len(nums) - 1:
            result.append(nums[-2])
        else:
            result.append(nums[i - 1] + nums[i + 1])

    return result
