def is_balanced(s: str) -> bool:
    if len(s) <= 1:
        return True

    # Precompute primes up to 94 (max possible difference)
    max_diff = 94
    is_prime = [True] * (max_diff + 1)
    is_prime[0] = is_prime[1] = False

    for i in range(2, int(max_diff**0.5) + 1):
        if is_prime[i]:
            for j in range(i * i, max_diff + 1, i):
                is_prime[j] = False

    # Check adjacent characters
    for i in range(len(s) - 1):
        diff = abs(ord(s[i]) - ord(s[i + 1]))
        if not is_prime[diff]:
            return False

    return True
